export interface AgentsMdInput {
  agents: Array<{
    name: string;
    route: string;
    model: string;
    auth: string;
    tools: string[];
  }>;
  tools: Array<{
    name: string;
    description: string;
  }>;
  prompts: string[];
}

export function generateAgentsMd(input: AgentsMdInput): string {
  const lines: string[] = [
    "# AGENTS.md",
    "",
    "> Auto-generated by fabrk build",
    "",
  ];

  if (input.agents.length > 0) {
    lines.push("## Agents", "");
    for (const a of input.agents) {
      lines.push(`### ${a.name}`, "");
      lines.push(`- **Route:** \`${a.route}\``);
      lines.push(`- **Model:** ${a.model}`);
      lines.push(`- **Auth:** ${a.auth}`);
      if (a.tools.length > 0) {
        lines.push(`- **Tools:** ${a.tools.join(", ")}`);
      }
      lines.push("");
    }
  } else {
    lines.push("No agents defined.", "");
  }

  if (input.tools.length > 0) {
    lines.push("## Tools", "");
    for (const t of input.tools) {
      lines.push(`### ${t.name}`, "");
      lines.push(`${t.description}`, "");
    }
  }

  if (input.prompts.length > 0) {
    lines.push("## Prompts", "");
    for (const p of input.prompts) {
      lines.push(`- ${p}`);
    }
    lines.push("");
  }

  return lines.join("\n");
}
